query getOrder($orderId: ID!) {
  order(id: $orderId) {
    name
    email
    customer {
      id
      email
    }
  }
}

query getMultipleOrders($orderIds: [ID!]!) {
  nodes(ids: $orderIds) {
    ... on Order {
      id
      name
      lineItems(first: 10) {
        edges {
          node {
            title
            quantity
            image {
              url
            }
            originalTotalSet { shopMoney { amount } }
            discountedTotalSet { shopMoney { amount } }
          }
        }
      }
    }
  }
}

parameters.jsCode:
const supabase = $('Select rows from a table').item.json;

// Mapeo pedido → nombre de sucursal
const SUCURSALES = {
  pedido_rules:        'Rules Outlet',
  pedido_oakley:       'Rules Oakley',
  pedido_thenorthface: 'Rules The North Face',
  pedido_surfin:       'Surfin',
  pedido_nuance:       'Nuance',
  pedido_nuancelodge:  'Nuance Lodge',
  pedido_melia:        'Meliá Sierra Nevada'
};

// Construir mapa: GID de pedido → nombre de sucursal
const orderMap = {};
for (const [key, nombre] of Object.entries(SUCURSALES)) {
  if (supabase[key]) {
    orderMap['gid://shopify/Order/' + supabase[key]] = nombre;
  }
}

// Procesar pedidos de GraphQL1
const rawOrders = $('GraphQL1').item.json?.data?.nodes || [];
const pedidos = rawOrders
  .filter(o => o !== null)
  .map(order => {
    const sucursal = orderMap[order.id] || 'Tienda';
    const items = (order.lineItems?.edges || []).map(({ node: p }) => {
      const orig = parseFloat(p.originalTotalSet?.shopMoney?.amount || 0);
      const disc = parseFloat(p.discountedTotalSet?.shopMoney?.amount || 0);
      return {
        titulo:    p.title,
        cantidad:  p.quantity,
        imagen:    p.image?.url || null,
        precio_original:   orig,
        precio_descuento:  disc,
        ahorro:            parseFloat((orig - disc).toFixed(2))
      };
    });
    const totalAhorro = items.reduce((acc, i) => acc + i.ahorro, 0);
    return {
      id:       order.id,
      nombre:   order.name,
      sucursal: sucursal,
      items:    items,
      totalAhorro: parseFloat(totalAhorro.toFixed(2))
    };
  })
  .filter(o => o.items.length > 0);

const totalAhorroGlobal = pedidos.reduce((acc, p) => acc + p.totalAhorro, 0);

return [{
  json: {
    Nombre:               supabase.Nombre || '',
    correo:               supabase.correo || '',
    sucursal_rules:       parseInt(supabase.sucursal_rules || 0),
    sucursal_oakley:      parseInt(supabase.sucursal_oakley || 0),
    sucursal_thenorthface:parseInt(supabase.sucursal_thenorthface || 0),
    sucursal_surfin:      parseInt(supabase.sucursal_surfin || 0),
    sucursal_nuance:      parseInt(supabase.sucursal_nuance || 0),
    sucursal_nuancelodge: parseInt(supabase.sucursal_nuancelodge || 0),
    sucursal_melia:       parseInt(supabase.sucursal_melia || 0),
    pedido_rules:         supabase.pedido_rules || null,
    pedido_oakley:        supabase.pedido_oakley || null,
    pedido_thenorthface:  supabase.pedido_thenorthface || null,
    pedido_surfin:        supabase.pedido_surfin || null,
    pedido_nuance:        supabase.pedido_nuance || null,
    pedido_nuancelodge:   supabase.pedido_nuancelodge || null,
    pedido_melia:         supabase.pedido_melia || null,
    pedidos:              pedidos,
    totalAhorroGlobal:    parseFloat(totalAhorroGlobal.toFixed(2))
  }
}];

